    // avoid problems by installing playwright
    logger.info('Installing Chromium install for og:image generation...')
    const result = exec('npx', ['playwright', 'install', 'chromium'])
    const output = await result

    if (output.stderr) {
      result.process?.stderr?.pipe(process.stderr)
    }
    if (output.stdout) {
      result.process?.stdout?.pipe(process.stdout)
    }
    if (output.exitCode !== 0) {
      logger.error('Failed to install Playwright dependency for og:image generation. Trying anyway...')
    }

    result.kill()
    logger.info('Installed Chromium install for og:image generation.')
    installedChromium = true
  })()
}

for (const token of tokens) {
  // Dark mode overrides
  if (isDarkMode) {
    const darkMatch = token.match(DARK_MODE_PREFIX_RE)
    if (darkMatch) {
      const resolved = resolveDarkToken(darkMatch[1]!, renderWidth)
      if (resolved)
        darkOverrideGroups.add(getUtilityGroup(resolved))
      continue
    }
  }
  // Responsive overrides (e.g. lg:flex should override base hidden)
  const respMatch = token.match(RESPONSIVE_PREFIX_RE)
  if (respMatch) {
    const bp = respMatch[1]!
    const baseClass = respMatch[2]!
    const breakpointWidth = BREAKPOINTS[bp]
    if (breakpointWidth && renderWidth >= breakpointWidth)
      responsiveOverrideGroups.add(getUtilityGroup(baseClass))
  }
}

if (node.style?.fontFamily) {
  const families = (node.style.fontFamily as string).split(',').map((f: string) => f.trim().replace(RE_QUOTES, ''))
  const resolved: string[] = []
  const seen = new Set<string>()
  const addUnique = (name: string) => {
    if (!seen.has(name.toLowerCase())) {
      resolved.push(name)
      seen.add(name.toLowerCase())
    }
  }
  for (const f of families) {
    // Check if this is an original family name that was split into subsets
    const chain = resolveSubsetChain(f, subsetChains)
    if (chain) {
      chain.forEach(addUnique)
      continue
    }
    // Resolve case-insensitive match against loaded families
    addUnique(lookupFontFamily(f, loadedFamilies) || f)
  }
  // Append remaining loaded families as fallback for missing glyphs
  for (const family of loadedFamilies)
    addUnique(family)
  node.style.fontFamily = resolved.map((f: string) => `"${f}"`).join(', ')
}

return await withTakumiLock(state, lockTimeout, () => {
    endLockWait()
    return timings.measure('render-takumi', async () => {
      await loadFontsIntoRenderer(state, fonts)

      const rootStyle = nodes.style ?? {}
      if (fontFamilyOverride) {
        const chain = subsetChains.get(fontFamilyOverride)
        if (chain) {
          rootStyle.fontFamily = chain.map(f => `"${f}"`).join(', ')
        }
        else if (state.loadedFamilies.has(fontFamilyOverride)) {
          rootStyle.fontFamily = fontFamilyOverride
        }
      }
      nodes.style = rootStyle
      rewriteFontFamilies(nodes, state.loadedFamilies, subsetChains)

      return state.renderer.render(nodes, renderOptions)
    })
  }, endLockWait)

try {
  return (await Promise.resolve(next())) as RequestServerResult<any, any, any>
} catch (error: unknown) {
  if (error instanceof EvlogError || (error && typeof error === 'object' && (error as Error).name === 'EvlogError')) {
    const evlogError = error as EvlogError

    try {
      const { useRequest } = await import('nitro/context')
      const req = useRequest()
      const log = req.context?.log as RequestLogger | undefined
      log?.error(evlogError)
    } catch {
      // ignore
    }

    // Throw as Response so frameworks (TanStack Start, SolidStart, etc.) pass it through
    throw new Response(JSON.stringify(evlogError.toJSON()), {
      status: evlogError.status || 500,
      headers: { 'Content-Type': 'application/json' },
    })
  }
  throw error
}

return {
  name: 'evlog:client-inject',

  configResolved(config) {
    isDev = config.command === 'serve'
  },

  transformIndexHtml() {
    const config: Record<string, unknown> = {}
    config.service = clientOptions.service ?? 'client'
    if (clientOptions.console !== undefined) config.console = clientOptions.console
    config.pretty = clientOptions.pretty ?? isDev
    if (clientOptions.minLevel !== undefined) config.minLevel = clientOptions.minLevel
    if (clientOptions.transport) config.transport = clientOptions.transport

    const configJson = JSON.stringify(config)

    return [
      {
        tag: 'script',
        attrs: { type: 'module' },
        children: `import{initLog}from'evlog/client'\ninitLog(${configJson})`,
        injectTo: 'head-prepend',
      },
    ]
  },
}

if (error && typeof error === 'object' && 'data' in error) {
  const { data, message: fetchMessage, statusCode: fetchStatusCode, status: fetchStatus } = error as FetchError & { status?: number }

  // Support both nested data.data (fetch response) and direct data (EvlogError)
  const evlogData = (data?.data ?? data) as { code?: string, why?: string, fix?: string, link?: string } | undefined

  return {
    // Prefer statusText, then statusMessage (or message) for the error message
    message: data?.statusText || data?.statusMessage || data?.message || fetchMessage || 'An error occurred',
    // Prefer status, then statusCode for the status value
    status: data?.status || data?.statusCode || fetchStatus || fetchStatusCode || 500,
    // Prefer the structured `data.code`, then `data.code` directly, then a top-level `error.code`
    code: pickCode(evlogData) ?? pickCode(data) ?? pickCode(error),
    why: evlogData?.why,
    fix: evlogData?.fix,
    link: evlogData?.link,
    raw: error,
  }
}

return defineDrain<TConfig>({
  name: options.name,
  resolve: options.resolve,
  send: async (events, config) => {
    if (events.length === 0) return
    const request = options.encode(events, config)
    if (!request) return
    const timeout = options.resolveTimeout?.(config)
      ?? (config as { timeout?: number }).timeout
      ?? options.timeout
      ?? DEFAULT_HTTP_TIMEOUT
    const retries = options.resolveRetries?.(config)
      ?? (config as { retries?: number }).retries
      ?? options.retries
    await httpPost({
      url: request.url,
      headers: request.headers,
      body: request.body,
      timeout,
      retries,
      label: options.name,
      source: options.name,
    })
  },
})

